                                  }
                                >
                                  升级
                                </Button>
                                <Button
                                  className="min-h-8"
                                  color="secondary"
                                  isDisabled={
                                    node.connectionStatus !== "online"
                                  }
                                  isLoading={node.rollbackLoading}
                                  size="sm"
                                  variant="flat"
                                  onPress={() => handleRollbackNode(node)}
                                >
                                  回退
                                </Button>
                              </div>
                            )}
                            <div
                              className={`grid gap-1.5 ${isRemoteNode ? "grid-cols-1" : "grid-cols-2"}`}
                            >
                              {!isRemoteNode && (
                                <Button
                                  className="min-h-8"
                                  color="primary"
                                  size="sm"
                                  variant="flat"
                                  onPress={() => handleEdit(node)}
