                              <Button
                                className="min-h-8"
                                color="danger"
                                size="sm"
                                variant="flat"
                                onPress={() => handleDelete(node)}
                              >
                                删除
                              </Button>
                            </div>
                          </div>
                        </CardBody>
                      </Card>
                    )}
                  </SortableItem>
                );
              })}
            </div>
